module RefModule(CLK, UP, DOWN, COUNT);
input CLK;
input UP;
input DOWN;
output reg [2:0] COUNT;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (UP) begin
        COUNT <= COUNT + 1;
    end else if (DOWN) begin
        COUNT <= COUNT - 1;
    end
end

endmodule
